Here's a pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("http://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [ExpectedException(typeof(HttpRequestException))]
    public async Task FetchAsync_Throws_OnError()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await fetcher.FetchAsync("http://example.com");
    }

    [TestMethod]
    [ExpectedException(typeof(TaskCanceledException))]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        var handler = new DelayedHttpMessageHandler(TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        using var cts = new CancellationTokenSource();
        var fetcher = new DataFetcher(client);

        cts.Cancel(); // cancel immediately
        await fetcher.FetchAsync("http://example.com", cts.Token);
    }

    [TestMethod]
    [Timeout(3000)] // failsafe: test must complete within 3s
    public async Task FetchAsync_RespectsTimeout()
    {
        var handler = new DelayedHttpMessageHandler(TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler) { Timeout = TimeSpan.FromMilliseconds(100) };
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("http://example.com"));
    }
}
```

**Test helpers:**

```csharp
public class MockHttpMessageHandler : HttpMessageHandler
{
    private readonly string _content;
    private readonly HttpStatusCode _statusCode;

    public MockHttpMessageHandler(string content, HttpStatusCode statusCode)
    {
        _content = content;
        _statusCode = statusCode;
    }

    protected override Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        cancellationToken.ThrowIfCancellationRequested();
        var response = new HttpResponseMessage(_statusCode)
        {
            Content = new StringContent(_content)
        };
        return Task.FromResult(response);
    }
}

public class DelayedHttpMessageHandler : HttpMessageHandler
{
    private readonly TimeSpan _delay;
    public DelayedHttpMessageHandler(TimeSpan delay) => _delay = delay;

    protected override async Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        await Task.Delay(_delay, cancellationToken); // throws if cancelled
        return new HttpResponseMessage(HttpStatusCode.OK);
    }
}
```

**Key points:**

- Subclass `HttpMessageHandler` to mock `HttpClient` without a real network
- `[Timeout(ms)]` acts as a test-level safeguard against hangs
- Use `CancellationTokenSource` to verify cancellation propagation
- Set `HttpClient.Timeout` to test the built-in timeout behavior
- Always call `cancellationToken.ThrowIfCancellationRequested()` in mocks to faithfully simulate real behavior
